// Inline the screenplay-PDF fonts into an ops module, so runScriptDoc → scriptToPdf can embed the real
// design faces with NO font files to ship at runtime - the same "inline the asset" trick as the
// playable-runtime blob. The fonts are gzipped then base64'd; the generated module gunzips one lazily on
// first use. Commit the generated file.
//
// The three type ROLES of the readable-script design, embedded as real faces:
//   serif (reading: dialogue / narration / headings) = Newsreader   (R / SemiBold / Italic / SemiBoldItalic)
//   sans  (cues / labels / tags)                      = Inter        (R / SemiBold)
//   mono  (conditions / {@property} / game events)    = IBM Plex Mono (R)
// Newsreader / Inter / Plex Mono are Latin subsets, so two fallbacks keep full coverage:
//   symbol = DejaVu Sans     - the marks the layout uses (◇ ↪ ⚙ ‹ ›), maths / arrows, Greek, Cyrillic
//   emoji  = Noto Emoji      - monochrome emoji
// Licences: Newsreader / Inter / IBM Plex Mono / Noto Emoji = SIL OFL 1.1 (fonts/OFL.txt); DejaVu =
// Bitstream Vera (fonts/DejaVu-LICENSE.txt). The raw .ttf files live in ../fonts (git-ignored - re-download
// from the URLs in fonts/README.md).
import { gzipSync } from "node:zlib";
import { readFileSync as read, writeFileSync as write } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

const here = dirname(fileURLToPath(import.meta.url));
const fontsDir = resolve(here, "../fonts");
const out = resolve(here, "../src/script-fonts.ts");

const FILES = {
  serif: "Newsreader-Regular.ttf",
  serifBold: "Newsreader-SemiBold.ttf",
  serifItalic: "Newsreader-Italic.ttf",
  serifBoldItalic: "Newsreader-SemiBoldItalic.ttf",
  sans: "Inter-Regular.ttf",
  sansBold: "Inter-SemiBold.ttf",
  mono: "IBMPlexMono-Regular.ttf",
  symbol: "DejaVuSans.ttf",
  emoji: "NotoEmoji-Regular.ttf",
};

const entries = Object.entries(FILES).map(([key, file]) => {
  const b64 = gzipSync(read(resolve(fontsDir, file)), { level: 9 }).toString("base64");
  return `  ${key}: "${b64}",`;
}).join("\n");

const banner =
  "// GENERATED by scripts/gen-fonts-blob.mjs - do not edit by hand. Re-run after a font change.\n" +
  "// Embedded screenplay-PDF faces: Newsreader (serif), Inter (sans), IBM Plex Mono (mono), with DejaVu\n" +
  "// Sans (symbol / non-Latin fallback) + Noto Emoji, gzipped + base64'd, gunzipped lazily. Licences:\n" +
  "// Newsreader / Inter / IBM Plex Mono / Noto Emoji = SIL OFL 1.1 (fonts/OFL.txt); DejaVu = Bitstream\n" +
  "// Vera (fonts/DejaVu-LICENSE.txt).\n";

const keyType = Object.keys(FILES).map((k) => `"${k}"`).join(" | ");
const body = `import { gunzipSync } from "node:zlib";

/** A registered screenplay-PDF face key. */
export type ScriptFontKey = ${keyType};

/** The gzip+base64 font blobs, keyed by face. Decoded lazily by \`scriptFont\`. */
const RAW: Record<ScriptFontKey, string> = {
${entries}
};

const cache: Partial<Record<ScriptFontKey, Buffer>> = {};
/** The decoded TTF bytes for an embedded face. Decompressed once on first use (a PDF export), then cached
 *  - other ops paths never pay it. */
export function scriptFont(key: ScriptFontKey): Buffer {
  return (cache[key] ??= gunzipSync(Buffer.from(RAW[key]!, "base64")));
}
`;

write(out, banner + body);
const bytes = Buffer.byteLength(banner + body);
console.log(`wrote ${out} (${Math.round(bytes / 1024)} KB of base64 font data)`);
